"""Секция pipeline (таб «Общее» в GUI): индекс result, число потоков для этапов пайплайна."""from __future__ import annotationsfrom typing import Any# Ключи секции в config.jsonKEY_DISCOVERY_THREADS = "discovery_threads"KEY_EXTRACT_THREADS = "extract_threads"KEY_IMAGE_PROCESSING_THREADS = "image_processing_threads"KEY_MARKDOWN_THREADS = "markdown_threads"KEY_TAGGING_THREADS = "tagging_threads"KEY_CREATE_DOCUMENTS_INDEX = "create_documents_index"DISCOVERY_THREADS_DEFAULT = 1CREATE_DOCUMENTS_INDEX_DEFAULT = TrueDISCOVERY_THREADS_ONLY = 1  # всегда 1EXTRACT_THREADS_MIN, EXTRACT_THREADS_MAX = 1, 16EXTRACT_THREADS_DEFAULT = 4IMAGE_PROCESSING_THREADS_MIN, IMAGE_PROCESSING_THREADS_MAX = 1, 8IMAGE_PROCESSING_THREADS_DEFAULT = 4MARKDOWN_THREADS_MIN, MARKDOWN_THREADS_MAX = 1, 8MARKDOWN_THREADS_DEFAULT = 4TAGGING_THREADS_MIN, TAGGING_THREADS_MAX = 1, 8TAGGING_THREADS_DEFAULT = 4class PipelineConfig:    """Секция pipeline в config.json: индекс, параллелизм этапов (таб «Общее» в GUI)."""    @staticmethod    def create_documents_index_enabled(pipeline: dict[str, Any] | None) -> bool:        """Читает create_documents_index из секции pipeline с умолчанием True."""        from src.modules.project.sections.tagging_config import TaggingConfig        p = pipeline if isinstance(pipeline, dict) else {}        return TaggingConfig.coerce_bool(            p.get(KEY_CREATE_DOCUMENTS_INDEX), CREATE_DOCUMENTS_INDEX_DEFAULT        )    @staticmethod    def get_default() -> dict[str, Any]:        """Возвращает словарь умолчаний для секции pipeline."""        return {            KEY_DISCOVERY_THREADS: DISCOVERY_THREADS_DEFAULT,            KEY_CREATE_DOCUMENTS_INDEX: CREATE_DOCUMENTS_INDEX_DEFAULT,            KEY_EXTRACT_THREADS: EXTRACT_THREADS_DEFAULT,            KEY_IMAGE_PROCESSING_THREADS: IMAGE_PROCESSING_THREADS_DEFAULT,            KEY_MARKDOWN_THREADS: MARKDOWN_THREADS_DEFAULT,            KEY_TAGGING_THREADS: TAGGING_THREADS_DEFAULT,        }    @staticmethod    def validate(data: Any) -> list[str]:        """Проверяет данные секции pipeline. Возвращает список сообщений об ошибках (пустой — данные валидны)."""        errors: list[str] = []        if not isinstance(data, dict):            errors.append("Pipeline: ожидается объект (dict).")            return errors        v = data.get(KEY_CREATE_DOCUMENTS_INDEX)        if v is not None and not isinstance(v, bool):            errors.append(                f"Pipeline: поле {KEY_CREATE_DOCUMENTS_INDEX} должно быть true/false (bool)."            )        v = data.get(KEY_DISCOVERY_THREADS)        if v is not None and (not isinstance(v, int) or v != DISCOVERY_THREADS_ONLY):            errors.append(f"Pipeline: {KEY_DISCOVERY_THREADS} должен быть равен {DISCOVERY_THREADS_ONLY}.")        v = data.get(KEY_EXTRACT_THREADS)        if v is not None and (not isinstance(v, int) or v < EXTRACT_THREADS_MIN or v > EXTRACT_THREADS_MAX):            errors.append(                f"Pipeline: {KEY_EXTRACT_THREADS} должен быть целым числом от {EXTRACT_THREADS_MIN} до {EXTRACT_THREADS_MAX}."            )        v = data.get(KEY_IMAGE_PROCESSING_THREADS)        if v is not None and (            not isinstance(v, int) or v < IMAGE_PROCESSING_THREADS_MIN or v > IMAGE_PROCESSING_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_IMAGE_PROCESSING_THREADS} должен быть целым числом от {IMAGE_PROCESSING_THREADS_MIN} до {IMAGE_PROCESSING_THREADS_MAX}."            )        v = data.get(KEY_MARKDOWN_THREADS)        if v is not None and (            not isinstance(v, int) or v < MARKDOWN_THREADS_MIN or v > MARKDOWN_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_MARKDOWN_THREADS} должен быть целым числом от {MARKDOWN_THREADS_MIN} до {MARKDOWN_THREADS_MAX}."            )        v = data.get(KEY_TAGGING_THREADS)        if v is not None and (            not isinstance(v, int) or v < TAGGING_THREADS_MIN or v > TAGGING_THREADS_MAX        ):            errors.append(                f"Pipeline: {KEY_TAGGING_THREADS} должен быть целым числом от {TAGGING_THREADS_MIN} до {TAGGING_THREADS_MAX}."            )        return errors